// Test: stackalloc Span<nint> and Span<nuint>

// Signed native-sized integers
Span<nint> signed = stackalloc nint[4];
for (int i = 0; i < signed.Length; i++)
    signed[i] = i * 10;

Console.WriteLine("Span<nint> via stackalloc:");
foreach (var v in signed)
    Console.WriteLine($"  {v}");

// Unsigned native-sized integers
Span<nuint> unsigned = stackalloc nuint[3];
unsigned[0] = nuint.MinValue;
unsigned[1] = 42;
unsigned[2] = nuint.MaxValue;

Console.WriteLine("Span<nuint> via stackalloc:");
foreach (var v in unsigned)
    Console.WriteLine($"  {v}");

Console.WriteLine($"\nnint size : {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");
Console.WriteLine("\nSuccess — stackalloc with nint/nuint works!");

